impl Solution { pub fn unmarked_sum_array(nums: Vec<i32>, queries: Vec<Vec<i32>>) -> Vec<i64> { let mut black_s: i64 = nums.iter().map(|&x| x as i64).sum(); let mut black_m = vec![false; nums.len()]; let mut black_p: Vec<usize> = (0..nums.len()).collect(); black_p.sort_unstable_by(|&a, &b| nums[a].cmp(&nums[b]).then(a.cmp(&b))); let (mut black_it, mut black_res) = (black_p.into_iter(), Vec::new()); for q in queries { let (idx, k) = (q[0] as usize, q[1]); if !black_m[idx] { black_m[idx] = true; black_s -= nums[idx] as i64; } let mut black_c = 0; while black_c < k { if let Some(i) = black_it.next() { if !black_m[i] { black_m[i] = true; black_s -= nums[i] as i64; black_c += 1; } } else { break; } } black_res.push(black_s); } black_res } }